mapper.select:
SELECT * FROM t_production_process_tracking
WHERE production_order_id = #{productionOrderId}
  AND tenant_id = #{tenantId}
ORDER BY bundle_no, process_order

SELECT * FROM t_production_process_tracking
WHERE cutting_bundle_id = #{cuttingBundleId}
  AND tenant_id = #{tenantId}
ORDER BY process_order

SELECT production_order_id AS productionOrderId, COALESCE(NULLIF(TRIM(process_name),''), NULLIF(TRIM(process_code),''), 'unknown') AS processName, process_code AS processCode, SUM(quantity) AS scannedQty FROM t_production_process_tracking WHERE scan_status = 'scanned' AND tenant_id = #{tenantId} AND production_order_id IN
#{id}
GROUP BY production_order_id, COALESCE(NULLIF(TRIM(process_name),''), NULLIF(TRIM(process_code),''), 'unknown'), process_code

SELECT * FROM t_production_process_tracking
WHERE cutting_bundle_id = #{cuttingBundleId}
  AND process_code = #{processCode}
  AND tenant_id = #{tenantId}
LIMIT 1

SELECT * FROM t_production_process_tracking
WHERE cutting_bundle_id = #{cuttingBundleId}
  AND process_name = #{processName}
  AND tenant_id = #{tenantId}
LIMIT 1

mapper.delete:
DELETE FROM t_production_process_tracking
WHERE production_order_id = #{productionOrderId}
  AND tenant_id = #{tenantId}

mapper.select:
SELECT production_order_id AS orderId, process_name AS processName, COUNT(DISTINCT cutting_bundle_id) AS scannedBundleCount FROM t_production_process_tracking WHERE scan_status = 'scanned' AND cutting_bundle_id IS NOT NULL AND cutting_bundle_id != '' AND production_order_id IN
#{id}
AND tenant_id = #{tenantId}
GROUP BY production_order_id, process_name
